# Process each blog file
updated = 0
for filename, sections in BLOG_CONTENT.items():
    filepath = os.path.join(RESOURCES_DIR, filename)
    if not os.path.exists(filepath):
        print(f'  SKIP: {filename} not found')
        continue

    with open(filepath, 'r', encoding='utf-8') as f:
        content = f.read()

    if '<h2>Overview</h2>' not in content:
        print(f'  SKIP: {filename} not thin')
        continue

    # Find the start of content (first <h2>) and end (CTA div with linear-gradient)
    first_h2 = content.find('<h2>Overview</h2>')
    cta_start = content.find('<div style="background: linear-gradient(135deg')

    if first_h2 == -1 or cta_start == -1:
        print(f'  SKIP: {filename} markers not found')
        continue

    # Build new content HTML
    new_html = ''
    for h2, body in sections:
        new_html += f'                                    <h2>{h2}</h2>\n                                    {body}\n'

    # Replace the content between first H2 and CTA div
    content = content[:first_h2] + new_html + content[cta_start:]

    with open(filepath, 'w', encoding='utf-8') as f:
        f.write(content)
    updated += 1
    print(f'  Rewritten: {filename} ({len(sections)} sections)')

print(f'\nTotal blogs rewritten: {updated}')
